// ============================================================
// PDF GENERATOR - ใบสรุปงานซ่อม
// ============================================================
function machGrid(rows) {
  let html = '<table style="width:100%;border-collapse:collapse;background:#eff6ff;border-radius:10px;overflow:hidden;margin-bottom:12px;table-layout:fixed">';
  rows.forEach(([label, val], i) => {
    const border = i < rows.length-1 ? 'border-bottom:1px solid #dbeafe' : '';
    const safeVal = String(val||'—');
    // ถ้ายาวเกิน 60 ตัว ตัดแสดงใน 2 บรรทัด
    const displayVal = safeVal.length > 80
      ? `<span style="word-break:break-all;overflow-wrap:anywhere">${safeVal}</span>`
      : safeVal;
    html += '<tr>'
      + `<td style="padding:6px 12px;${border};color:#1d4ed8;font-size:10px;font-weight:700;width:38%;vertical-align:top;white-space:nowrap">${label}</td>`
      + `<td style="padding:6px 12px;${border};font-weight:700;font-size:10.5px;color:#1e3a5f;word-break:break-word;overflow-wrap:anywhere">${displayVal}</td>`
      + '</tr>';
  });
  html += '</table>';
  return html;
}

