// ── Filter machines by vendor ──
// ── QR Code Scanner — ค้นหาเครื่องแอร์ ──
function openQRScannerOverlay() {
  // (fullscreen overlay scanner — kept for reference)
  // ปัจจุบันใช้ openQRScanner() ซึ่งใช้ qr-modal HTML แทน
  // Check camera support
  if (!navigator.mediaDevices?.getUserMedia) {
    showToast('⚠️ Browser นี้ไม่รองรับ Camera');
    return;
  }

  const ov = document.createElement('div');
  ov.style.cssText = 'position:fixed;inset:0;z-index:9900;background:#000;display:flex;flex-direction:column';

  // Header
  ov.innerHTML = `
    <div style="display:flex;align-items:center;justify-content:space-between;padding:14px 16px;background:rgba(0,0,0,0.8);flex-shrink:0">
      <div style="color:white;font-size:0.95rem;font-weight:800">📷 สแกน QR Code เครื่องแอร์</div>
      <button id="qr-close" style="width:34px;height:34px;border-radius:50%;background:rgba(255,255,255,0.15);border:none;color:white;font-size:1.1rem;cursor:pointer">✕</button>
    </div>
    <div style="flex:1;position:relative;overflow:hidden;display:flex;align-items:center;justify-content:center">
      <video id="qr-video-2" playsinline autoplay muted style="width:100%;height:100%;object-fit:cover"></video>
      <!-- Viewfinder -->
      <div style="position:absolute;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none">
        <div style="position:relative;width:240px;height:240px">
          <!-- corners -->
          <div style="position:absolute;top:0;left:0;width:40px;height:40px;border-top:4px solid #fff;border-left:4px solid #fff;border-radius:4px 0 0 0"></div>
          <div style="position:absolute;top:0;right:0;width:40px;height:40px;border-top:4px solid #fff;border-right:4px solid #fff;border-radius:0 4px 0 0"></div>
          <div style="position:absolute;bottom:0;left:0;width:40px;height:40px;border-bottom:4px solid #fff;border-left:4px solid #fff;border-radius:0 0 0 4px"></div>
          <div style="position:absolute;bottom:0;right:0;width:40px;height:40px;border-bottom:4px solid #fff;border-right:4px solid #fff;border-radius:0 0 4px 0"></div>
          <!-- scan line -->
          <div id="qr-scanline" style="position:absolute;left:4px;right:4px;height:2px;background:linear-gradient(90deg,transparent,#c8102e,transparent);top:0;animation:qrScan 2s linear infinite"></div>
        </div>
      </div>
      <!-- overlay darkening outside viewfinder -->
      <div style="position:absolute;inset:0;background:rgba(0,0,0,0.45);clip-path:polygon(0 0,100% 0,100% 100%,0 100%,0 calc(50% - 120px),calc(50% - 120px) calc(50% - 120px),calc(50% - 120px) calc(50% + 120px),calc(50% + 120px) calc(50% + 120px),calc(50% + 120px) calc(50% - 120px),0 calc(50% - 120px));pointer-events:none"></div>
    </div>
    <div style="padding:12px 16px 28px;background:rgba(0,0,0,0.8);flex-shrink:0">
      <div id="qr-status-2" style="color:rgba(255,255,255,0.7);font-size:0.78rem;text-align:center;margin-bottom:12px">วางกล้องตรง QR Code บนป้ายเครื่องแอร์</div>
      <!-- Manual input fallback -->
      <div style="display:flex;gap:8px">
        <input id="qr-manual" type="text" placeholder="พิมพ์ Air ID / Serial เพื่อค้นหาแทน..." 
          style="flex:1;padding:10px 14px;border-radius:10px;border:1.5px solid rgba(255,255,255,0.2);background:rgba(255,255,255,0.1);color:white;font-size:0.85rem;font-family:inherit;outline:none"
          oninput="this.style.borderColor=this.value?'#c8102e':'rgba(255,255,255,0.2)'"
          onkeydown="if(event.key==='Enter')qrManualSearch(this.value)"/>
        <button onclick="qrManualSearch(document.getElementById('qr-manual').value)"
          style="padding:10px 16px;background:#c8102e;color:white;border:none;border-radius:10px;font-size:0.82rem;font-weight:700;cursor:pointer;font-family:inherit">ค้นหา</button>
      </div>
    </div>`;

  // Add scan animation CSS
  if (!document.getElementById('qr-style')) {
    const s = document.createElement('style');
    s.id = 'qr-style';
    s.textContent = '@keyframes qrScan { 0%{top:4px} 50%{top:calc(100% - 6px)} 100%{top:4px} }';
    document.head.appendChild(s);
  }

  document.body.appendChild(ov);

  let stream = null;
  let scanning = true;
  let animFrame = null;

  // Start camera
  navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: false })
    .then(s => {
      stream = s;
      const video = ov.querySelector('#qr-video');
      video.srcObject = s;
      video.play();
      // Try BarcodeDetector API
      if ('BarcodeDetector' in window) {
        const detector = new BarcodeDetector({ formats: ['qr_code'] });
        const scan = async () => {
          if (!scanning) return;
          try {
            const barcodes = await detector.detect(video);
            if (barcodes.length > 0) {
              scanning = false;
              const raw = barcodes[0].rawValue;
              ov.querySelector('#qr-status').innerHTML = `<span style="color:#4ade80">✅ สแกนได้: <b>${raw}</b></span>`;
              navigator.vibrate?.([100, 50, 100]);
              setTimeout(() => qrFoundMachine(raw, ov, stream), 600);
              return;
            }
          } catch(e) {}
          animFrame = requestAnimationFrame(scan);
        };
        video.addEventListener('loadedmetadata', () => { animFrame = requestAnimationFrame(scan); });
      } else {
        // BarcodeDetector not supported — show manual only
        ov.querySelector('#qr-status').innerHTML = '<span style="color:#fde68a">⚠️ Browser ไม่รองรับ auto-scan — พิมพ์ Air ID ด้านล่างแทนได้</span>';
      }
    })
    .catch(err => {
      ov.querySelector('#qr-status').innerHTML = '<span style="color:#fca5a5">⚠️ ไม่สามารถเปิดกล้องได้ — ' + (err.name === 'NotAllowedError' ? 'กรุณาอนุญาต Camera' : err.message) + '</span>';
    });

  // Close
  function closeScanner() {
    scanning = false;
    if (animFrame) cancelAnimationFrame(animFrame);
    if (stream) stream.getTracks().forEach(t => t.stop());
    ov.remove();
  }
  ov.querySelector('#qr-close').onclick = closeScanner;
  ov.querySelector('#qr-manual').focus();

  // Manual search helper (closure)
  window._qrOv = ov;
  window._qrStream = stream;
  window._qrClose = closeScanner;
}

function qrManualSearch(val) {
  const q = (val||'').trim();
  if (!q) return;
  qrFoundMachine(q, window._qrOv, window._qrStream);
}

function qrFoundMachine(raw, ov, stream) {
  // ค้นหาจาก serial / Air ID / QR value
  const q = raw.trim().toUpperCase();
  // QR อาจมี prefix เช่น "AIRCON:Pm1S001" หรือแค่ "Pm1S001"
  const serial = q.includes(':') ? q.split(':').pop() : q;
  const found = db.machines.find(m =>
    (m.serial||'').toUpperCase() === serial ||
    (m.serial||'').toUpperCase().includes(serial) ||
    serial.includes((m.serial||'').toUpperCase())
  );

  if (window._qrClose) window._qrClose();

  if (found) {
    // ไปที่หน้าเครื่องแอร์ + highlight
    goPage('machines');
    setTimeout(() => {
      const search = document.getElementById('mac-search');
      if (search) { search.value = found.serial; applyMachineFilter(); }
      setTimeout(() => {
        const row = document.querySelector(`[data-mid="${found.id}"]`);
        if (row) {
          row.scrollIntoView({ behavior: 'smooth', block: 'center' });
          row.style.background = '#fff5f6';
          row.style.outline = '2px solid var(--accent)';
          setTimeout(() => { row.style.background = ''; row.style.outline = ''; }, 2500);
        }
        showToast('✅ พบ: ' + found.name);
        // เปิด detail sheet
        setTimeout(() => openMachineSheet(found.id), 400);
      }, 400);
    }, 200);
  } else {
    // ไม่พบ — เปิดช่องค้นหาพร้อมค่า
    goPage('machines');
    setTimeout(() => {
      const search = document.getElementById('mac-search');
      if (search) { search.value = serial; applyMachineFilter(); }
      showToast('⚠️ ไม่พบเครื่องที่ตรงกับ: ' + serial);
    }, 200);
  }
}

function filterByVendor(vendor) {
  const sel = document.getElementById('mac-search');
  if (sel) {
    sel.value = vendor === 'ไม่ระบุ' ? '' : vendor;
    applyMachineFilter();
  }
}

